client_script:
let isSubmitting = false;

frappe.web_form.validate = async () => {
    
    if (isSubmitting) {
        frappe.msgprint("Already submitting... please wait");
        return false;
    }

    let user = frappe.web_form.get_value("user");
    let company = frappe.web_form.get_value("company");
    let quotation_id = frappe.web_form.get_value("quotation_form");

    let form_name = "Insurance Form";
    let form_status = frappe.web_form.get_value("insurance_copy_received");
    let form_document = frappe.web_form.get_value("insurance_copy_document");

    if (!form_document) {
        frappe.msgprint("Please attach file before submitting");
        return false;
    }
    
    isSubmitting = true;

    const btn = $(".web-form-actions .btn-primary");
    const originalText = btn.text();

    btn.prop("disabled", true);
    btn.text("Saving...");

    try {
        const r = await frappe.call({
            method: "alms_app.api.car_process.car_form_fill",
            type: "POST",
            args: { 
                user,
                company,
                quotation_id,
                form_name,
                form_status,
                form_document,
            }
        });

        if (!r.message || r.message.status !== "success") {
            frappe.msgprint({
                title: "Error",
                indicator: "red",
                message: r.message?.message || "Something went wrong"
            });
            return false;
        }

        return true;

    } catch (e) {
        frappe.msgprint({
            title: "Server Error",
            indicator: "red",
            message: "API failed. Please try again."
        });
        return false;
    }
};
